package com.kisman.cc.gui.alts;

import java.util.ArrayList;

import com.mojang.authlib.yggdrasil.YggdrasilUserAuthentication;

public class AltManager {
	public static ArrayList<AltEntry> alts = new ArrayList<AltEntry>();

	public static boolean isLoggedIn(String email) {
		for(AltEntry alt : alts) {
			if(alt.getEmail().equals(email)) {
				return true;
			}
		}
		return false;
	}

	public static void logIn(String email, String password, boolean isAlt) {
		try {
			if(isAlt) {
				AltManager.alts.add(new AltEntry(email, password));
			} else {
				AltManager.alts.add(new AltEntry(email, password));
			}
		} catch (Exception e) {
			e.printStackTrace();
		}
	}

	public static void logOut(String email) {
		for(AltEntry alt : alts) {
			if(alt.getEmail().equals(email)) {
				alts.remove(alt);
			}
		}
	}
}
